class DetailedErrorInterceptor(grpc.ServerInterceptor):
    def intercept_service(self, continuation, handler_call_details):
        return continuation(handler_call_details)


class ServiceState:
    def __init__(self):
        self.lock = threading.Lock()
        self.request_count = 0
        self.error_count = 0
        self.active_requests = 0
        self.last_error = None
        self.start_time = datetime.now()
    
    def get_state(self):
        with self.lock:
            return {
                'request_count': self.request_count,
                'error_count': self.error_count,
                'active_requests': self.active_requests,
                'last_error': self.last_error,
                'uptime_seconds': (datetime.now() - self.start_time).total_seconds()
            }
    
    def increment_requests(self):
        with self.lock:
            self.request_count += 1
            self.active_requests += 1
    
    def decrement_active(self):
        with self.lock:
            self.active_requests -= 1
    
    def record_error(self, error_info):
        with self.lock:
            self.error_count += 1
            self.last_error = error_info


def create_error_details(exception, service_state, method_name, request_data=None):
    error_details = {
        'timestamp': datetime.now().isoformat(),
        'method': method_name,
        'error_type': type(exception).__name__,
        'error_message': str(exception),
        'traceback': traceback.format_exc(),
        'stack_frames': []
    }
    
    tb = sys.exc_info()[2]
    if tb:
        for frame_summary in traceback.extract_tb(tb):
            error_details['stack_frames'].append({
                'filename': frame_summary.filename,
                'line': frame_summary.lineno,
                'function': frame_summary.name,
                'code': frame_summary.line
            })
    
    error_details['service_state'] = service_state.get_state()
    
    if request_data:
        try:
            error_details['request_data'] = str(request_data)
        except:
            error_details['request_data'] = 'Unable to serialize request data'
    
    error_details['system_info'] = {
        'python_version': sys.version,
        'platform': sys.platform
    }
    
    return error_details


def handle_service_error(context, exception, service_state, method_name, request_data=None):
    error_details = create_error_details(exception, service_state, method_name, request_data)
    
    service_state.record_error({
        'timestamp': error_details['timestamp'],
        'error_type': error_details['error_type'],
        'method': method_name
    })
    
    detailed_message = json.dumps(error_details, indent=2)
    
    if isinstance(exception, ValueError):
        context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
        context.set_details(f"Invalid argument error\n{detailed_message}")
    elif isinstance(exception, KeyError):
        context.set_code(grpc.StatusCode.NOT_FOUND)
        context.set_details(f"Resource not found\n{detailed_message}")
    elif isinstance(exception, PermissionError):
        context.set_code(grpc.StatusCode.PERMISSION_DENIED)
        context.set_details(f"Permission denied\n{detailed_message}")
    elif isinstance(exception, TimeoutError):
        context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
        context.set_details(f"Operation timeout\n{detailed_message}")
    elif isinstance(exception, ConnectionError):
        context.set_code(grpc.StatusCode.UNAVAILABLE)
        context.set_details(f"Service unavailable\n{detailed_message}")
    else:
        context.set_code(grpc.StatusCode.INTERNAL)
        context.set_details(f"Internal server error\n{detailed_message}")
    
    print(f"ERROR in {method_name}: {exception}")
    print(detailed_message)


